insert into public.localization_keys(translation_key,module,source_text,description,is_system,is_active,updated_at)
select translation_key,module,nullif(ar_text,''),'Synchronized from PETATOE v9.4.23 production dictionary',true,true,now() from petatoe_localization_sync
on conflict (translation_key) do update set module=excluded.module,source_text=excluded.source_text,is_active=true,updated_at=now();

insert into public.localization_values(key_id,language_code,translated_text,status,version,approved_at,updated_at)
select k.id,'ar',s.ar_text,'approved',coalesce(v.version,0)+1,now(),now()
from petatoe_localization_sync s join public.localization_keys k using(translation_key)
left join public.localization_values v on v.key_id=k.id and v.language_code='ar'
where s.ar_text<>''
on conflict (key_id,language_code) do update set translated_text=excluded.translated_text,status='approved',version=case when public.localization_values.translated_text is distinct from excluded.translated_text then public.localization_values.version+1 else public.localization_values.version end,approved_at=now(),updated_at=now();

insert into public.localization_values(key_id,language_code,translated_text,status,version,approved_at,updated_at)
select k.id,'en',s.en_text,'approved',coalesce(v.version,0)+1,now(),now()
from petatoe_localization_sync s join public.localization_keys k using(translation_key)
left join public.localization_values v on v.key_id=k.id and v.language_code='en'
where s.en_text<>''
on conflict (key_id,language_code) do update set translated_text=excluded.translated_text,status='approved',version=case when public.localization_values.translated_text is distinct from excluded.translated_text then public.localization_values.version+1 else public.localization_values.version end,approved_at=now(),updated_at=now();

-- Only deactivate obsolete system keys. User-created keys are preserved.
update public.localization_keys k set is_active=false,updated_at=now()
where k.is_system=true and k.is_active=true and not exists(select 1 from petatoe_localization_sync s where s.translation_key=k.translation_key);

-- Remove stale pending rows where an approved value now exists.
delete from public.localization_queue q using public.localization_keys k,public.localization_values v
where q.translation_key=k.translation_key and v.key_id=k.id and v.language_code=q.target_language and v.status='approved' and q.status='pending';

commit;

-- Exact parity verification. Expected: all booleans true and all issue counts zero.
with expected as (select 3936::bigint active_keys,3936::bigint ar_values,3936::bigint en_values),
actual as (
 select
  (select count(*) from public.localization_keys where is_active and is_system) active_system_keys,
  (select count(*) from public.localization_values v join public.localization_keys k on k.id=v.key_id where k.is_active and k.is_system and v.status='approved' and v.language_code='ar') approved_ar,
  (select count(*) from public.localization_values v join public.localization_keys k on k.id=v.key_id where k.is_active and k.is_system and v.status='approved' and v.language_code='en') approved_en,
  (select count(*) from public.localization_queue q where q.status='pending' and exists(select 1 from public.localization_keys k where k.is_active and k.translation_key=q.translation_key)) pending_active,
  (select count(*) from public.localization_keys where is_active and is_system and btrim(coalesce(source_text,''))='') empty_source,
  (select count(*) from public.localization_values v join public.localization_keys k on k.id=v.key_id where k.is_active and k.is_system and v.status='approved' and btrim(coalesce(v.translated_text,''))='') empty_approved
)
select jsonb_build_object(
 'expected_active_keys',e.active_keys,'actual_active_system_keys',a.active_system_keys,'keys_match',a.active_system_keys=e.active_keys,
 'expected_ar',e.ar_values,'actual_approved_ar',a.approved_ar,'arabic_match',a.approved_ar=e.ar_values,
 'expected_en',e.en_values,'actual_approved_en',a.approved_en,'english_match',a.approved_en=e.en_values,
 'pending_active',a.pending_active,'empty_source',a.empty_source,'empty_approved',a.empty_approved,
 'parity_ok',a.active_system_keys=e.active_keys and a.approved_ar=e.ar_values and a.approved_en=e.en_values and a.pending_active=0 and a.empty_source=0 and a.empty_approved=0,
 'dictionary_sha256','1f916887523328e3d02c1816b63f7a57777a0aa787749e850a00c45951c2ef44'
) as localization_parity_result from expected e cross join actual a;
